/**
 * Unit Test: i18n (Internationalization)
 * タスク6.2: クライアントサイド単体テスト
 */

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { detectBrowserLocale, getMessages, type SupportedLocale } from '@/client/lib/theme/i18n';

describe('i18n (Internationalization)', () => {
  describe('detectBrowserLocale', () => {
    let originalNavigator: Navigator;

    beforeEach(() => {
      originalNavigator = global.navigator;
    });

    afterEach(() => {
      global.navigator = originalNavigator;
    });

    it('日本語ブラウザを検知する', () => {
      Object.defineProperty(global.navigator, 'language', {
        writable: true,
        value: 'ja-JP',
      });

      const locale = detectBrowserLocale();
      expect(locale).toBe('ja');
    });

    it('英語ブラウザを検知する', () => {
      Object.defineProperty(global.navigator, 'language', {
        writable: true,
        value: 'en-US',
      });

      const locale = detectBrowserLocale();
      expect(locale).toBe('en');
    });

    it('中国語ブラウザを検知する', () => {
      Object.defineProperty(global.navigator, 'language', {
        writable: true,
        value: 'zh-CN',
      });

      const locale = detectBrowserLocale();
      expect(locale).toBe('zh');
    });

    it('韓国語ブラウザを検知する', () => {
      Object.defineProperty(global.navigator, 'language', {
        writable: true,
        value: 'ko-KR',
      });

      const locale = detectBrowserLocale();
      expect(locale).toBe('ko');
    });

    it('サポート外の言語はデフォルト（ja）にフォールバックする', () => {
      Object.defineProperty(global.navigator, 'language', {
        writable: true,
        value: 'fr-FR',
      });

      const locale = detectBrowserLocale();
      expect(locale).toBe('ja');
    });

    it('大文字小文字を区別せず検知する', () => {
      Object.defineProperty(global.navigator, 'language', {
        writable: true,
        value: 'EN-US',
      });

      const locale = detectBrowserLocale();
      expect(locale).toBe('en');
    });
  });

  describe('getMessages', () => {
    it('日本語メッセージを取得する', () => {
      const messages = getMessages('ja');

      expect(messages.placeholder).toBe('メッセージを入力してください');
      expect(messages.send).toBe('送信');
      expect(messages.loading).toBe('応答を生成中...');
      expect(messages.error).toBe('エラーが発生しました');
      expect(messages.retry).toBe('再試行');
      expect(messages.charLimitError).toBe('256文字以内で入力してください');
      expect(messages.piiError).toBe('個人情報は入力しないでください');
      expect(messages.welcome).toBe(
        'こんにちは！ワールドマスターズゲームズ2027関西のサポートチャットです 🎉\n大会に関するご質問にAIがお答えします。\nメッセージを入力してください。'
      );
    });

    it('英語メッセージを取得する', () => {
      const messages = getMessages('en');

      expect(messages.placeholder).toBe('Enter your message');
      expect(messages.send).toBe('Send');
      expect(messages.loading).toBe('Generating response...');
      expect(messages.error).toBe('An error occurred');
      expect(messages.retry).toBe('Retry');
      expect(messages.charLimitError).toBe('Please enter within 256 characters');
      expect(messages.piiError).toBe('Please do not enter personal information');
      expect(messages.welcome).toBe(
        'Hello! Welcome to World Masters Games 2027 Kansai Support Chat 🎉\nOur AI will answer your questions about the games.\nPlease enter your message.'
      );
    });

    it('中国語メッセージを取得する', () => {
      const messages = getMessages('zh');

      expect(messages.placeholder).toBe('请输入消息');
      expect(messages.send).toBe('发送');
      expect(messages.loading).toBe('正在生成回复...');
      expect(messages.error).toBe('发生错误');
      expect(messages.retry).toBe('重试');
      expect(messages.charLimitError).toBe('请在256个字符以内输入');
      expect(messages.piiError).toBe('请勿输入个人信息');
      expect(messages.welcome).toBe(
        '您好！欢迎使用2027年世界大师运动会关西支持聊天 🎉\nAI将回答您关于大会的问题。\n请输入您的消息。'
      );
    });

    it('韓国語メッセージを取得する', () => {
      const messages = getMessages('ko');

      expect(messages.placeholder).toBe('메시지를 입력하세요');
      expect(messages.send).toBe('전송');
      expect(messages.loading).toBe('응답 생성 중...');
      expect(messages.error).toBe('오류가 발생했습니다');
      expect(messages.retry).toBe('재시도');
      expect(messages.charLimitError).toBe('256자 이내로 입력해주세요');
      expect(messages.piiError).toBe('개인정보를 입력하지 마세요');
      expect(messages.welcome).toBe(
        '안녕하세요! 2027 월드마스터즈게임 간사이 지원 챗봇입니다 🎉\nAI가 대회에 관한 질문에 답변해 드립니다.\n메시지를 입력해 주세요.'
      );
    });

    it('すべてのロケールで必須メッセージキーが存在する', () => {
      const locales: SupportedLocale[] = ['ja', 'en', 'zh', 'ko'];
      const requiredKeys: (keyof ReturnType<typeof getMessages>)[] = [
        'placeholder',
        'send',
        'loading',
        'error',
        'retry',
        'charLimitError',
        'piiError',
        'welcome',
      ];

      for (const locale of locales) {
        const messages = getMessages(locale);
        for (const key of requiredKeys) {
          expect(messages[key]).toBeDefined();
          expect(messages[key].length).toBeGreaterThan(0);
        }
      }
    });
  });
});

'use client';

/**
 * Chat Window Component
 * チャットウィンドウ全体（ヘッダー、メッセージ表示エリア、入力エリア）
 */

import { useChatUI } from '@/client/hooks/useChatUI';
import { ChatMessage, ChatLoadingIndicator } from './ChatMessage';
import { ChatInput } from './ChatInput';

interface ChatWindowProps {
  isOpen: boolean;
  onClose: () => void;
}

export function ChatWindow({ isOpen, onClose }: ChatWindowProps) {
  const {
    messages_i18n,
    messagesEndRef,
    messages,
    input,
    isLoading,
    error,
    reload,
    handleInputChange,
    handleFormSubmit,
  } = useChatUI();

  if (!isOpen) return null;

  return (
    <>
      {/* モバイル用オーバーレイ（768px未満） */}
      <div
        className="fixed inset-0 bg-black/50 z-[1000] md:hidden animate-fadeIn"
        onClick={onClose}
        aria-hidden="true"
      />

      {/* チャットウィンドウ */}
      <div
        className={`
          fixed z-[1001]
          flex flex-col
          bg-white
          shadow-2xl

          /* モバイル: 全画面表示 */
          bottom-0 left-0 right-0 top-0
          w-full h-full
          animate-slideUpMobile

          /* PC: 右下固定表示 */
          md:bottom-5 md:right-5 md:left-auto md:top-auto
          md:w-[400px] md:h-[600px]
          md:rounded-2xl
          md:animate-slideInDesktop
        `}
        role="dialog"
        aria-labelledby="chat-title"
        aria-modal="true"
      >
        {/* ヘッダー */}
        <div className="bg-[#E31E24] text-white px-4 py-3 md:py-4 flex items-center justify-between flex-shrink-0 md:rounded-t-2xl">
          <div className="flex items-center space-x-3">
            {/* WMGロゴ */}
            <div className="w-10 h-10 md:w-12 md:h-12 rounded-full bg-white flex items-center justify-center flex-shrink-0 p-1 overflow-hidden">
              <img
                src="/wmg2027-logo.png"
                alt="WMG2027 Logo"
                className="w-full h-full object-cover object-[center_65%]"
              />
            </div>

            {/* タイトル */}
            <div className="flex-1">
              <h2 id="chat-title" className="text-base md:text-lg font-bold leading-tight">
                WMG2027 サポートチャット
              </h2>
              <p className="text-xs md:text-sm text-white/95 leading-tight">
                お気軽にご質問ください
              </p>
            </div>
          </div>

          {/* 閉じるボタン */}
          <button
            onClick={onClose}
            className="w-8 h-8 md:w-9 md:h-9 flex items-center justify-center rounded-full hover:bg-white/20 transition-colors focus:outline-none focus:ring-2 focus:ring-white/50"
            aria-label="チャットを閉じる"
          >
            <svg
              xmlns="http://www.w3.org/2000/svg"
              fill="none"
              viewBox="0 0 24 24"
              strokeWidth={2.5}
              stroke="currentColor"
              className="w-6 h-6"
            >
              <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        {/* メッセージ表示エリア */}
        <div className="flex-1 overflow-y-auto bg-gray-50 px-4 py-4 md:px-4 md:py-4">
          {/* ウェルカムメッセージ */}
          {messages.length === 0 && (
            <div className="mb-4">
              <div className="flex justify-start items-start">
                {/* ボットアイコン（WMGロゴ） */}
                <div className="flex-shrink-0 w-8 h-8 md:w-10 md:h-10 rounded-full bg-white flex items-center justify-center mr-2 shadow-md p-1 overflow-hidden">
                  <img
                    src="/wmg2027-logo.png"
                    alt="WMG2027 Logo"
                    className="w-full h-full object-cover object-[center_65%]"
                  />
                </div>

                {/* メッセージ */}
                <div className="flex flex-col items-start max-w-[85%]">
                  <div className="bg-white text-gray-800 rounded-2xl px-4 py-3 shadow-[0_2px_8px_rgba(0,0,0,0.1)]">
                    <p className="text-sm md:text-[15px] whitespace-pre-wrap break-words leading-relaxed">
                      {messages_i18n.welcome}
                    </p>
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* メッセージリスト */}
          {messages.map(message => (
            <ChatMessage key={message.id} message={message} />
          ))}

          {/* ローディングインジケータ */}
          {isLoading && <ChatLoadingIndicator />}

          {/* エラー表示 */}
          {error && (
            <div className="bg-red-50 border border-red-200 text-red-800 p-3 rounded-lg mb-4">
              <p className="font-semibold">{messages_i18n.error}</p>
              <p className="text-sm mt-1">{error.message}</p>
              <button
                onClick={() => reload()}
                className="mt-2 text-sm underline hover:no-underline"
              >
                {messages_i18n.retry}
              </button>
            </div>
          )}

          <div ref={messagesEndRef} />
        </div>

        {/* 入力エリア */}
        <div className="flex-shrink-0">
          <ChatInput
            input={input}
            isLoading={isLoading}
            onInputChange={handleInputChange}
            onSubmit={handleFormSubmit}
          />
        </div>
      </div>
    </>
  );
}

